module shift_register(
    input [7:0] d,
    input clk,
    input load,
    input s_in,
    output reg [7:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt)
    begin
        if (load)
            q = d;
        else
            q = {s_in, q[7:1]};
    end
endmodule
